# 并查集
class UnionFindSet:
    def __init__(self, n):
        self.fa = [idx for idx in range(n)]
        self.count = n

    def find(self, x):
        if x != self.fa[x]:
            self.fa[x] = self.find(self.fa[x])
            return self.fa[x]
        return x

    def union(self, x, y):
        x_fa = self.find(x)
        y_fa = self.find(y)

        if x_fa != y_fa:
            self.fa[y_fa] = x_fa
            self.count -= 1


m, n = map(int, input().split())

matrix = []
for i in range(m):
    matrix.append(list(map(int, input().split())))

ufs = UnionFindSet(m * n)

# 上下左右的偏移量
offsets = ((-1, 0), (1, 0), (0, -1), (0, 1))

for i in range(m):
    for j in range(n):
        # 注意下面这层for是常量级的,就四次循环,因此,这里的时间复杂度还是O(n*m),即
        for offsetX, offsetY in offsets:
            newI = i + offsetX
            newJ = j + offsetY

            if 0 <= newI < m and 0 <= newJ < n and abs(matrix[i][j] - matrix[newI][newJ]) <= 1:
                ufs.union(i * n + j, newI * n + newJ)

total = m * n

# ufs.count是连通分量的个数,如果只有一个连通分量,那么代表所有的点都可达
if ufs.count == 1:
    print(total)
else:
    # count字典用于统计指向同一个祖先下点的个数,即每个连通分量下的点个数
    count = {}

    # 这个for循环是有必要的,确保每个点都指向祖先
    for i in range(total):
        ufs.find(i)
        fa = ufs.fa[i]
        count[fa] = count.get(fa, 0) + 1

    # 取最大个数
    print(max(count.values()))
